{/*CustomButton recibe un texto y una ruta de enlace*/}

function Button({ buttonLabel, buttonUrl, onClick, customClasName }) {

  const navigate = useNavigate();

  return (
    <>
      {onClick ? (
        <button onClick={onClick} className={`btn btn-primary ${customClasName}`}>
          {buttonLabel}
        </button>
      ) : (
        <a href={buttonUrl} className={`btn btn-primary ${customClasName}`}>
          {buttonLabel}
        </a>
      )}
    </>
  );
}

export default Button;
